import mongoose, { Schema, Model } from 'mongoose';
import { UserDocument } from '../types';

const userSchema = new Schema<UserDocument>(
  {
    email: {
      type: String,
      required: true,
      unique: true,
      lowercase: true,
      trim: true,
    },
    name: {
      type: String,
      trim: true,
    },
    picture: {
      type: String,
    },
    provider: {
      type: String,
      enum: ['google', 'email'],
      required: true,
    },
    googleId: {
      type: String,
      sparse: true,
      unique: true,
    },
  },
  {
    timestamps: true,
  }
);

// Indexes are defined in the schema fields above

let User: Model<UserDocument>;

try {
  User = mongoose.model<UserDocument>('User');
} catch {
  User = mongoose.model<UserDocument>('User', userSchema);
}

export default User;

