import mongoose, { Schema, Model } from 'mongoose';
import { OtpDocument } from '../types';

const otpSchema = new Schema<OtpDocument>(
  {
    email: {
      type: String,
      required: true,
      lowercase: true,
      trim: true,
    },
    otp: {
      type: String,
      required: true,
    },
    expiresAt: {
      type: Date,
      required: true,
      index: { expires: 0 }, // TTL index - auto delete
    },
    used: {
      type: Boolean,
      default: false,
    },
    ipAddress: {
      type: String,
    },
    createdAt: {
      type: Date,
      default: Date.now,
    },
  },
  {
    timestamps: false,
  }
);

// Indexes are defined in the schema fields above

let Otp: Model<OtpDocument>;

try {
  Otp = mongoose.model<OtpDocument>('Otp');
} catch {
  Otp = mongoose.model<OtpDocument>('Otp', otpSchema);
}

export default Otp;

